refentry.refsect1:
&reftitle.parameters;
string
Входная строка (string) для разбора.
&strings.scanf.parameter.format;
vars
Необязательные переменные, которые передаются по ссылке и которые будут содержать значения с результатами разбора строки.

  &reftitle.examples;

   Пример использования функции sscanf


<?php

// Получаем серийный номер
list($serial) = sscanf("SN/2350001", "SN/%d");

// и дату изготовления
$mandate = "January 01 2000";

list($month, $day, $year) = sscanf($mandate, "%s %d %d");

echo "Узел $serial изготовили: $year-" . substr($month, 0, 3) . "-$day\n";

?>




   Функция вернёт количество присвоенных значений,
   если передали необязательные аргументы.



    Пример использования функции sscanf с необязательными аргументами



<?php

// Получаем имя автора и формируем запись в формате DocBook
$auth = "24\tLewis Carroll";

$n = sscanf($auth, "%d\t%s %s", $id, $first, $last);

echo "<author id='$id'>
    <firstname>$first</firstname>
    <surname>$last</surname>
</author>\n";

?>
